        /// <returns><see cref="Task"/>&lt;<see cref="ICreateHistoricalTransactionAtBankApiResponse"/>&gt;</returns>
        Task<ICreateHistoricalTransactionAtBankApiResponse> CreateHistoricalTransactionAtBankAsync(string bankid, CreateHistoricalTransactionAtBankRequest createHistoricalTransactionAtBankRequest, System.Threading.CancellationToken cancellationToken = default);

        /// <summary>
        /// Create Historical Transactions 
        /// </summary>
        /// <remarks>
