        /// </summary>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="viewid">The VIEWID identifier</param>
        /// <param name="accountotp">The ACCOUNTOTP identifier</param>
        /// <param name="createTransactionRequestAccountRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="ICreateTransactionRequestAccountOtpApiResponse"/>&gt;</returns>
        public async Task<ICreateTransactionRequestAccountOtpApiResponse?> CreateTransactionRequestAccountOtpOrDefaultAsync(string bankid, string accountid, string viewid, string accountotp, CreateTransactionRequestAccountRequest createTransactionRequestAccountRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await CreateTransactionRequestAccountOtpAsync(bankid, accountid, viewid, accountotp, createTransactionRequestAccountRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

        /// <summary>
