        public async Task<ICreateTransactionRequestCardApiResponse?> CreateTransactionRequestCardOrDefaultAsync(string card, CreateTransactionRequestCardRequest createTransactionRequestCardRequest, System.Threading.CancellationToken cancellationToken = default)
