        /// </summary>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="ethsendtransaction">The ETHSENDTRANSACTION identifier</param>
        /// <param name="createTransactionRequestEthereumeSendTransactionRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="ICreateTransactionRequestEthereumeSendTransactionApiResponse"/>&gt;</returns>
        public async Task<ICreateTransactionRequestEthereumeSendTransactionApiResponse?> CreateTransactionRequestEthereumeSendTransactionOrDefaultAsync(string bankid, string accountid, string ethsendtransaction, CreateTransactionRequestEthereumeSendTransactionRequest createTransactionRequestEthereumeSendTransactionRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await CreateTransactionRequestEthereumeSendTransactionAsync(bankid, accountid, ethsendtransaction, createTransactionRequestEthereumeSendTransactionRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

