        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="ICreateTransactionRequestFreeFormApiResponse"/>&gt;</returns>
        public async Task<ICreateTransactionRequestFreeFormApiResponse?> CreateTransactionRequestFreeFormOrDefaultAsync(string bankid, string accountid, string viewid, string freeform, CreateTransactionRequestFreeFormRequest createTransactionRequestFreeFormRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await CreateTransactionRequestFreeFormAsync(bankid, accountid, viewid, freeform, createTransactionRequestFreeFormRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

