        /// </summary>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="hold">The HOLD identifier</param>
        /// <param name="createTransactionRequestFreeFormRequest">Request body</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="ICreateTransactionRequestHoldApiResponse"/>&gt;</returns>
        public async Task<ICreateTransactionRequestHoldApiResponse?> CreateTransactionRequestHoldOrDefaultAsync(string bankid, string accountid, string hold, CreateTransactionRequestFreeFormRequest createTransactionRequestFreeFormRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await CreateTransactionRequestHoldAsync(bankid, accountid, hold, createTransactionRequestFreeFormRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

