        /// </summary>
        /// <param name="bankid">The BANKID identifier</param>
        /// <param name="accountid">The ACCOUNTID identifier</param>
        /// <param name="viewid">The VIEWID identifier</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns><see cref="Task"/>&lt;<see cref="IGetTransactionRequestsApiResponse"/>&gt;</returns>
        public async Task<IGetTransactionRequestsApiResponse?> GetTransactionRequestsOrDefaultAsync(string bankid, string accountid, string viewid, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await GetTransactionRequestsAsync(bankid, accountid, viewid, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

